from dataclasses import dataclass
from typing import Literal

RiskTier = Literal["APPROVED", "REVIEW", "BLOCKED"]

@dataclass
class LicenceRiskAssessment:
    source: DataSourceRecord
    ml_use_analysis: str       # Narrative legal analysis
    derivative_work_risk: str  # NONE / LOW / MEDIUM / HIGH
    copyleft_risk: str         # NONE / WEAK / STRONG
    web_tou_compliant: bool | None  # None if not web-scraped
    risk_tier: RiskTier
    assessed_by: str           # Name or team (IP counsel / Legal Ops)
    assessment_date: str       # ISO date

    def is_usable(self) -> bool:
        return self.risk_tier == "APPROVED"

    def blocks_commercial_use(self) -> bool:
        return (
            self.risk_tier == "BLOCKED" or
            self.copyleft_risk == "STRONG" or
            (self.source.ml_use_clause == "PROHIBITED")
        )

    def risk_summary(self) -> str:
        return (
            f"{self.source.name}: {self.risk_tier} | "
            f"ML use: {self.source.ml_use_clause} | "
            f"Copyleft: {self.copyleft_risk} | "
            f"Derivative risk: {self.derivative_work_risk}"
        )


@dataclass
class LicenceRiskRegister:
    assessments: list[LicenceRiskAssessment]

    def blocked_sources(self) -> list[LicenceRiskAssessment]:
        return [a for a in self.assessments if a.risk_tier == "BLOCKED"]

    def review_sources(self) -> list[LicenceRiskAssessment]:
        return [a for a in self.assessments if a.risk_tier == "REVIEW"]

    def approved_volume_gb(self) -> float:
        return sum(a.source.volume_gb for a in self.assessments if a.is_usable())

    def register_summary(self) -> str:
        total = len(self.assessments)
        approved = sum(1 for a in self.assessments if a.risk_tier == "APPROVED")
        review = sum(1 for a in self.assessments if a.risk_tier == "REVIEW")
        blocked = sum(1 for a in self.assessments if a.risk_tier == "BLOCKED")
        return (
            f"Licence Register: {total} sources — "
            f"{approved} APPROVED ({self.approved_volume_gb():.1f} GB) | "
            f"{review} REVIEW | {blocked} BLOCKED"
        )

@dataclass
class VendorTrainingDataAudit:
    vendor_name: str
    model_name: str
    model_version: str
    audit_date: str

    model_card_published: bool
    data_sources_documented: bool
    robots_txt_compliant: bool | None   # None if vendor has not disclosed
    ip_indemnification_offered: bool
    active_litigation: bool
    opt_out_signals_respected: bool | None

    def overall_risk(self) -> str:
        if not self.model_card_published or not self.data_sources_documented:
            return "HIGH — insufficient documentation"
        if self.active_litigation and not self.ip_indemnification_offered:
            return "HIGH — unindemnified litigation exposure"
        if self.robots_txt_compliant is False:
            return "HIGH — ToU non-compliance disclosed"
        if not self.ip_indemnification_offered:
            return "MEDIUM — no indemnification"
        if self.active_litigation:
            return "MEDIUM — indemnified but litigation ongoing"
        return "LOW — documented, indemnified, compliant"

    def audit_summary(self) -> str:
        return (
            f"{self.vendor_name} / {self.model_name} v{self.model_version}: "
            f"Risk={self.overall_risk()} | "
            f"ModelCard={'YES' if self.model_card_published else 'NO'} | "
            f"Indemnification={'YES' if self.ip_indemnification_offered else 'NO'} | "
            f"Litigation={'YES' if self.active_litigation else 'NO'}"
        )

from dataclasses import dataclass, field

@dataclass
class LicenceHealthReport:
    report_date: str
    register: LicenceRiskRegister
    new_blocked_since_last_report: list[str]    # source IDs
    tou_changes_detected: list[str]             # source IDs
    pending_negotiations: list[str]             # source IDs
    litigation_updates: list[str]               # free-text descriptions

    def requires_action(self) -> bool:
        return bool(
            self.new_blocked_since_last_report or
            self.tou_changes_detected or
            self.pending_negotiations
        )

    def executive_summary(self) -> str:
        parts = [f"Licence Health as of {self.report_date}:", self.register.register_summary()]
        if self.new_blocked_since_last_report:
            parts.append(
                f"ACTION REQUIRED: {len(self.new_blocked_since_last_report)} sources newly BLOCKED — "
                f"remove from pipeline: {', '.join(self.new_blocked_since_last_report)}"
            )
        if self.tou_changes_detected:
            parts.append(
                f"ToU CHANGES: {len(self.tou_changes_detected)} sources need re-review: "
                f"{', '.join(self.tou_changes_detected)}"
            )
        if self.litigation_updates:
            parts.append("LITIGATION: " + "; ".join(self.litigation_updates))
        return " | ".join(parts)
